namespace sv_8aff4caf62ba46809666cc1cf57bd307.Client.Models;

public sealed class ShipmentDetails
{
    public required string TrackingNumber { get; init; }
    public required string Status { get; init; }
    public required string Location { get; init; }
    public required DateTimeOffset EstimatedDelivery { get; init; }
    public required IReadOnlyList<StatusUpdate> StatusUpdates { get; init; }
}

public sealed class StatusUpdate
{
    public required DateTimeOffset Timestamp { get; init; }
    public required string Description { get; init; }
    public required string Location { get; init; }
}

using sv_8aff4caf62ba46809666cc1cf57bd307.Client.Models;

namespace sv_8aff4caf62ba46809666cc1cf57bd307.Client.Services;

public interface IShipmentService
{
    Task<ShipmentDetails?> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

using System.Net.Http.Json;
using sv_8aff4caf62ba46809666cc1cf57bd307.Client.Models;

namespace sv_8aff4caf62ba46809666cc1cf57bd307.Client.Services;

/// <summary>
/// WebAssembly implementation — calls the server API over HTTP.
/// </summary>
public sealed class ShipmentClientService(HttpClient http) : IShipmentService
{
    public async Task<ShipmentDetails?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var response = await http.GetAsync($"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);

        if (response.StatusCode == System.Net.HttpStatusCode.NotFound)
            return null;

        response.EnsureSuccessStatusCode();

        return await response.Content.ReadFromJsonAsync<ShipmentDetails>(ct);
    }
}

using sv_8aff4caf62ba46809666cc1cf57bd307.Client.Models;
using sv_8aff4caf62ba46809666cc1cf57bd307.Client.Services;

namespace sv_8aff4caf62ba46809666cc1cf57bd307.Services;

/// <summary>
/// Server-side implementation — simulates a slow backend with seeded data.
/// </summary>
public sealed class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, ShipmentDetails> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["TRK-1001"] = new ShipmentDetails
        {
            TrackingNumber = "TRK-1001",
            Status = "In Transit",
            Location = "Chicago, IL",
            EstimatedDelivery = new DateTimeOffset(2026, 6, 3, 17, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 27, 8, 0, 0, TimeSpan.Zero), Description = "Package picked up", Location = "New York, NY" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 28, 14, 30, 0, TimeSpan.Zero), Description = "Arrived at sorting facility", Location = "Philadelphia, PA" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 29, 6, 15, 0, TimeSpan.Zero), Description = "Departed sorting facility", Location = "Chicago, IL" },
            ]
        },
        ["TRK-1002"] = new ShipmentDetails
        {
            TrackingNumber = "TRK-1002",
            Status = "Delivered",
            Location = "San Francisco, CA",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 28, 12, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 25, 9, 0, 0, TimeSpan.Zero), Description = "Package picked up", Location = "Seattle, WA" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 26, 16, 45, 0, TimeSpan.Zero), Description = "In transit", Location = "Portland, OR" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 27, 20, 0, 0, TimeSpan.Zero), Description = "Out for delivery", Location = "San Francisco, CA" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 28, 10, 30, 0, TimeSpan.Zero), Description = "Delivered", Location = "San Francisco, CA" },
            ]
        },
        ["TRK-1003"] = new ShipmentDetails
        {
            TrackingNumber = "TRK-1003",
            Status = "Label Created",
            Location = "Miami, FL",
            EstimatedDelivery = new DateTimeOffset(2026, 6, 5, 18, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 29, 1, 0, 0, TimeSpan.Zero), Description = "Shipping label created", Location = "Miami, FL" },
            ]
        }
    };

    public async Task<ShipmentDetails?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);

        SeedData.TryGetValue(trackingNumber, out var shipment);
        return shipment;
    }
}

using sv_8aff4caf62ba46809666cc1cf57bd307.Client.Services;

namespace sv_8aff4caf62ba46809666cc1cf57bd307.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        app.MapGet("api/shipments/{trackingNumber}", async (
            string trackingNumber,
            IShipmentService service,
            CancellationToken ct) =>
        {
            var shipment = await service.GetShipmentAsync(trackingNumber, ct);
            return shipment is null ? Results.NotFound() : Results.Ok(shipment);
        });
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_8aff4caf62ba46809666cc1cf57bd307.Client.Models
@using sv_8aff4caf62ba46809666cc1cf57bd307.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracker> Logger
@implements IAsyncDisposable

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="shipment-loading">
        <p><em>Loading shipment @TrackingNumber&hellip;</em></p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="shipment-error" role="alert">
        <p>@_errorMessage</p>
        <button @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_shipment is null)
{
    <div class="shipment-not-found">
        <p>Shipment <strong>@TrackingNumber</strong> was not found.</p>
    </div>
}
else
{
    <div class="shipment-details">
        <h2>Shipment @_shipment.TrackingNumber</h2>
        <dl>
            <dt>Status</dt>
            <dd>@_shipment.Status</dd>
            <dt>Location</dt>
            <dd>@_shipment.Location</dd>
            <dt>Estimated Delivery</dt>
            <dd>@_shipment.EstimatedDelivery.ToString("f")</dd>
        </dl>

        <h3>Status Updates</h3>
        @if (_shipment.StatusUpdates.Count == 0)
        {
            <p>No status updates yet.</p>
        }
        else
        {
            <table>
                <thead>
                    <tr>
                        <th>Time</th>
                        <th>Description</th>
                        <th>Location</th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var update in _shipment.StatusUpdates)
                    {
                        <tr>
                            <td>@update.Timestamp.ToString("g")</td>
                            <td>@update.Description</td>
                            <td>@update.Location</td>
                        </tr>
                    }
                </tbody>
            </table>
        }
    </div>
}

@code {
    private ShipmentDetails? _shipment;
    private bool _loading;
    private string? _errorMessage;

    private CancellationTokenSource? _loadCts;
    private readonly CancellationTokenSource _disposeCts = new();

    [Parameter]
    public string TrackingNumber { get; set; } = string.Empty;

    protected override Task OnParametersSetAsync() => LoadShipmentAsync();

    private async Task LoadShipmentAsync()
    {
        // Cancel any in-flight request before starting a new one.
        await CancelPendingLoadAsync();

        _shipment = null;
        _errorMessage = null;
        _loading = true;

        // Link to the dispose token so leaving the page cancels immediately.
        var cts = CancellationTokenSource.CreateLinkedTokenSource(_disposeCts.Token);
        _loadCts = cts;

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, cts.Token);
        }
        catch (OperationCanceledException) when (cts.Token.IsCancellationRequested)
        {
            // Navigation away or parameter change — silently abandon.
            return;
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout fetching shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (TaskCanceledException ex) when (ex.InnerException is TimeoutException)
        {
            Logger.LogError(ex, "Timeout fetching shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error fetching shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong loading shipment details. Please try again.";
        }
        finally
        {
            _loading = false;
        }
    }

    private Task RetryAsync() => LoadShipmentAsync();

    private async Task CancelPendingLoadAsync()
    {
        if (_loadCts is not null)
        {
            await _loadCts.CancelAsync();
            _loadCts.Dispose();
            _loadCts = null;
        }
    }

    public async ValueTask DisposeAsync()
    {
        await _disposeCts.CancelAsync();
        _disposeCts.Dispose();

        if (_loadCts is not null)
        {
            _loadCts.Dispose();
            _loadCts = null;
        }
    }
}

