@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_8aff4caf62ba46809666cc1cf57bd307.Client.Models
@using sv_8aff4caf62ba46809666cc1cf57bd307.Client.Services
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracker> Logger
@implements IAsyncDisposable

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="shipment-loading">
        <p><em>Loading shipment @TrackingNumber&hellip;</em></p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="shipment-error" role="alert">
        <p>@_errorMessage</p>
        <button @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_shipment is null)
{
    <div class="shipment-not-found">
        <p>Shipment <strong>@TrackingNumber</strong> was not found.</p>
    </div>
}
else
{
    <div class="shipment-details">
        <h2>Shipment @_shipment.TrackingNumber</h2>
        <dl>
            <dt>Status</dt>
            <dd>@_shipment.Status</dd>
            <dt>Location</dt>
            <dd>@_shipment.Location</dd>
            <dt>Estimated Delivery</dt>
            <dd>@_shipment.EstimatedDelivery.ToString("f")</dd>
        </dl>

        <h3>Status Updates</h3>
        @if (_shipment.StatusUpdates.Count == 0)
        {
            <p>No status updates yet.</p>
        }
        else
        {
            <table>
                <thead>
                    <tr>
                        <th>Time</th>
                        <th>Description</th>
                        <th>Location</th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var update in _shipment.StatusUpdates)
                    {
                        <tr>
                            <td>@update.Timestamp.ToString("g")</td>
                            <td>@update.Description</td>
                            <td>@update.Location</td>
                        </tr>
                    }
                </tbody>
            </table>
        }
    </div>
}

@code {
    private ShipmentDetails? _shipment;
    private bool _loading;
    private string? _errorMessage;

    private CancellationTokenSource? _loadCts;
    private readonly CancellationTokenSource _disposeCts = new();

    [Parameter]
    public string TrackingNumber { get; set; } = string.Empty;

    protected override Task OnParametersSetAsync() => LoadShipmentAsync();

    private async Task LoadShipmentAsync()
    {
        // Cancel any in-flight request before starting a new one.
        await CancelPendingLoadAsync();

        _shipment = null;
        _errorMessage = null;
        _loading = true;

        // Link to the dispose token so leaving the page cancels immediately.
        var cts = CancellationTokenSource.CreateLinkedTokenSource(_disposeCts.Token);
        _loadCts = cts;

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, cts.Token);
        }
        catch (OperationCanceledException) when (cts.Token.IsCancellationRequested)
        {
            // Navigation away or parameter change — silently abandon.
            return;
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout fetching shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (TaskCanceledException ex) when (ex.InnerException is TimeoutException)
        {
            Logger.LogError(ex, "Timeout fetching shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error fetching shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong loading shipment details. Please try again.";
        }
        finally
        {
            _loading = false;
        }
    }

    private Task RetryAsync() => LoadShipmentAsync();

    private async Task CancelPendingLoadAsync()
    {
        if (_loadCts is not null)
        {
            await _loadCts.CancelAsync();
            _loadCts.Dispose();
            _loadCts = null;
        }
    }

    public async ValueTask DisposeAsync()
    {
        await _disposeCts.CancelAsync();
        _disposeCts.Dispose();

        if (_loadCts is not null)
        {
            _loadCts.Dispose();
            _loadCts = null;
        }
    }
}

